#include<bits/stdc++.h>
using namespace std;
long long x,n,m;
bool flag=false;
int main(void){
	cin>>x;
	m=x;
	for(long long i=2;i*i<=x;i++){
		if(x%i)continue;
		n=0;
		while(!(x%i)){
			x/=i;
			n++;
		}if(flag)cout<<"* ";
		if(n>1)cout<<i<<'^'<<n<<' ',flag=true;
		else cout<<i<<' ',flag=true;
	}if(x!=1){
		if(m!=x)cout<<"* "<<x;
		else cout<<x;
	}
    return false;
}
